agent_output:
{
  "domain_analysis": {
    "business_context": "Leave management module within an HR software system. Governs how employees accrue, request, consume, and carry over paid leave. This is a core HR process with direct labor-law and payroll implications.",
    "bounded_context": "Leave Management",
    "ubiquitous_language": [
      { "term": "Leave Balance", "definition": "The current number of accrued, unconsumed leave days an employee is entitled to use. Must be >= 0 at all times." },
      { "term": "Accrual", "definition": "The process by which leave days are earned. 1.5 days are credited per month worked." },
      { "term": "Leave Request", "definition": "A formal submission by an employee to take leave for a specified date range, subject to approval." },
      { "term": "Medical Leave", "definition": "A category of leave that may be submitted retroactively (within 5 calendar days of the leave date) when accompanied by a doctor's note." },
      { "term": "Working Days", "definition": "Business days excluding weekends and company-recognized holidays, used for advance-notice calculations." },
      { "term": "Doctor's Note", "definition": "A medical certificate from a licensed practitioner, required as supporting evidence for retroactive medical leave." },
      { "term": "Contract End Date", "definition": "The date on which an employee's employment contract terminates. Leave cannot extend beyond this date." },
      { "term": "Carry-Over", "definition": "The process of transferring unused leave balance from one calendar year to the next, capped at 10 days." },
      { "term": "Forfeiture", "definition": "The loss of unused leave days exceeding the 10-day carry-over cap at calendar year boundary." },
      { "term": "Approval", "definition": "A manager's decision to grant a leave request, which then consumes the employee's leave balance." },
      { "term": "Rejection", "definition": "A manager's decision to deny a leave request. No leave balance is consumed." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Employees accrue 1.5 days of leave per month worked.",
      "invariant": false,
      "invariant_justification": "The accrual rate of 1.5 days/month is a company policy that could be changed by HR leadership or renegotiated in employment contracts. It is not a state-integrity constraint.",
      "testable_assertion": "After an employee completes N full months of service, their total accrued leave equals N × 1.5 days (before any consumption or forfeiture)."
    },
    {
      "id": "BR-2",
      "rule": "An employee's leave balance must never go below zero.",
      "invariant": true,
      "invariant_justification": "A negative leave balance means the system granted leave the employee had not earned. This is a state-integrity violation — it represents consumption of a resource that does not exist.",
      "testable_assertion": "For any employee at any point in time: leaveBalance >= 0."
    },
    {
      "id": "BR-3",
      "rule": "Non-medical leave requests must be submitted at least 3 working days before the leave start date.",
      "invariant": false,
      "invariant_justification": "The 3-working-day advance notice window is an administrative policy. Management could adjust it (e.g., to 2 days or 5 days) without corrupting system state.",
      "testable_assertion": "A non-medical leave request is rejected by the system if the number of working days between submission date and leave start date is fewer than 3."
    },
    {
      "id": "BR-4",
      "rule": "Medical leave can be submitted retroactively within 5 calendar days of the leave date, provided a doctor's note is attached.",
      "invariant": false,
      "invariant_justification": "The 5-day retroactive window and the doctor's note requirement are policy-level rules that could be adjusted by HR. They do not protect data integrity per se.",
      "testable_assertion": "A medical leave request submitted up to 5 calendar days after the leave date is accepted by the system if and only if a doctor's note is attached. A medical leave request submitted more than 5 calendar days after the leave date is rejected."
    },
    {
      "id": "BR-5",
      "rule": "Only managers can approve or reject leave requests.",
      "invariant": true,
      "invariant_justification": "This is an authorization invariant. If a non-manager could approve leave, the system's access-control integrity is violated.",
      "testable_assertion": "The approve/reject actions on a leave request are only executable by users with the Manager role for the requesting employee."
    },
    {
      "id": "BR-6",
      "rule": "Rejected leave does not consume leave balance.",
      "invariant": true,
      "invariant_justification": "If rejected leave consumed balance, the system would be in a corrupt state — deducting a resource for a benefit not granted. This is a state-consistency constraint.",
      "testable_assertion": "When a leave request transitions to Rejected status, the employee's leave balance remains unchanged from its value before the request was submitted (or is restored if it was tentatively held)."
    },
    {
      "id": "BR-7",
      "rule": "A leave request's date range must not extend beyond the employee's contract end date.",
      "invariant": true,
      "invariant_justification": "Granting leave past a contract end date is a logical impossibility — the employee has no employment relationship during that period. This protects domain integrity.",
      "testable_assertion": "The system rejects any leave request where the leave end date > the employee's contract end date."
    },
    {
      "id": "BR-8",
      "rule": "At calendar year-end, unused leave above 10 days is forfeited. A maximum of 10 days may carry over to the next year.",
      "invariant": false,
      "invariant_justification": "The 10-day carry-over cap is a company policy threshold. It could be raised or lowered without violating data integrity.",
      "testable_assertion": "On January 1 of each year, an employee's carried-over balance equals min(previous_year_remaining_balance, 10)."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An employee has worked 4 full months with no leave taken",
      "when": "The system calculates their leave balance",
      "then": "The balance is 6.0 days (4 × 1.5)"
    },
    {
      "id": "AC-2",
      "given": "An employee has a leave balance of 2 days",
      "when": "They submit a non-medical leave request for 3 days",
      "then": "The system rejects the request due to insufficient balance"
    },
    {
      "id": "AC-3",
      "given": "An employee submits a non-medical leave request on a Monday",
      "when": "The requested leave start date is the following Wednesday (2 working days away)",
      "then": "The system rejects the request for insufficient advance notice (fewer than 3 working days)"
    },
    {
      "id": "AC-4",
      "given": "An employee submits a non-medical leave request on a Monday",
      "when": "The requested leave start date is the following Thursday (3 working days away)",
      "then": "The system accepts the request for advance-notice validation"
    },
    {
      "id": "AC-5",
      "given": "An employee was sick last Tuesday and it is now the following Sunday (5 calendar days later)",
      "when": "They submit a medical leave request for last Tuesday with a valid doctor's note attached",
      "then": "The system accepts the retroactive medical leave request"
    },
    {
      "id": "AC-6",
      "given": "An employee was sick 6 calendar days ago",
      "when": "They submit a medical leave request for that date with a doctor's note",
      "then": "The system rejects the request as it exceeds the 5-day retroactive submission window"
    },
    {
      "id": "AC-7",
      "given": "An employee submits a retroactive medical leave request within 5 days",
      "when": "No doctor's note is attached",
      "then": "The system rejects the request due to missing required documentation"
    },
    {
      "id": "AC-8",
      "given": "A manager reviews a pending leave request",
      "when": "The manager rejects the request",
      "then": "The employee's leave balance remains unchanged and the request status is set to Rejected"
    },
    {
      "id": "AC-9",
      "given": "An employee's contract ends on March 31",
      "when": "They submit a leave request for March 28 to April 2",
      "then": "The system rejects the request because the leave period spans beyond the contract end date"
    },
    {
      "id": "AC-10",
      "given": "An employee has 14 unused leave days on December 31",
      "when": "The calendar year rolls over to January 1",
      "then": "The employee's new balance is 10 days and 4 days are forfeited"
    },
    {
      "id": "AC-11",
      "given": "An employee has 8 unused leave days on December 31",
      "when": "The calendar year rolls over to January 1",
      "then": "The employee's new balance is 8 days (no forfeiture, as balance is at or below the 10-day cap)"
    },
    {
      "id": "AC-12",
      "given": "A manager approves a 2-day leave request for an employee with a balance of 5 days",
      "when": "The approval is recorded",
      "then": "The employee's leave balance is reduced to 3 days"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Employee submits leave starting exactly on their contract end date",
      "expected_behavior": "The request should be accepted (the contract end date is the last day of employment, so leave on that date is valid). A leave request ending after it must be rejected."
    },
    {
      "scenario": "Medical leave spans multiple days and is submitted retroactively — some days fall within the 5-day window and some do not",
      "expected_behavior": "Spec is ambiguous. Recommendation: measure the 5-day window from the earliest day of the medical leave period. If the earliest day is more than 5 calendar days ago, reject the entire request."
    },
    {
      "scenario": "Employee submits a leave request that straddles the calendar year boundary (e.g., Dec 29 to Jan 3)",
      "expected_behavior": "The leave should be deducted from the current year's balance. The carry-over calculation should apply after this deduction. The spec does not address this — it requires clarification."
    },
    {
      "scenario": "Partial month worked — employee joins mid-month",
      "expected_behavior": "Spec says 1.5 days per month worked but does not define whether partial months accrue pro-rata or require a full month. This needs HR policy clarification."
    },
    {
      "scenario": "Manager approves a leave request, then the employee's contract end date is moved earlier (e.g., early termination) so that approved leave now falls after the new contract end date",
      "expected_behavior": "Previously approved leave that now extends beyond the updated contract end date should be automatically invalidated and the balance restored. Spec is silent on this."
    },
    {
      "scenario": "Leave request is submitted exactly 3 working days in advance but a public holiday falls within that window",
      "expected_behavior": "The 3-working-day rule uses working days, so holidays must be excluded from the count. If a holiday reduces the effective working days below 3, the request should be rejected."
    },
    {
      "scenario": "Employee has 0 balance and submits a medical leave retroactively — they haven't yet accrued enough days",
      "expected_behavior": "The non-negative balance invariant (BR-2) still applies. Medical leave exempts the advance-notice rule, not the balance requirement. The request must be rejected unless there is an unpaid/special leave policy (not described in spec)."
    },
    {
      "scenario": "Carry-over runs, then accrual for January is added — ordering matters",
      "expected_behavior": "Carry-over forfeiture must be applied before January accrual is credited, otherwise the cap calculation would be incorrect."
    }
  ],

  "business_impact": {
    "financial": "Incorrect accrual or carry-over logic can lead to under- or over-granting of leave, translating directly to payroll errors. Overly generous errors create unfunded leave liabilities; overly restrictive errors create labor-law compliance risk and potential penalties.",
    "operational": "Leave management drives workforce scheduling. Incorrect balance tracking or approval workflows can cause staffing gaps or block legitimate leave, disrupting operations.",
    "user": "Employees expect accurate, transparent leave balances. Errors erode trust in the HR system and increase support burden. The retroactive medical leave feature is critical for employee well-being — a broken implementation could force sick employees to come to work.",
    "risk": "Labor law in most jurisdictions mandates minimum leave entitlements. A negative-balance bug or incorrect forfeiture could expose the company to regulatory action. The contract-end-date rule is also legally significant — leave granted post-termination could have unintended contractual implications.",
    "stakeholders_affected": [
      { "group": "Employees", "impact": "Primary users. Incorrect balances, rejected valid requests, or forfeited leave they should retain directly harms them." },
      { "group": "Managers", "impact": "Rely on the system for workforce planning. Incorrect leave data undermines scheduling decisions." },
      { "group": "HR Department", "impact": "Owns policy enforcement. Must trust the system to apply rules consistently. Errors generate manual exception handling." },
      { "group": "Payroll Team", "impact": "Leave balances feed into payroll calculations (leave encashment, payout at termination). Inaccurate balances cascade into pay errors." },
      { "group": "Finance / CFO", "impact": "Leave liabilities appear on the balance sheet. Incorrect carry-over logic misrepresents financial obligations." },
      { "group": "Legal / Compliance", "impact": "Must ensure leave policies comply with labor regulations. System bugs could create compliance violations." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec clearly defines the core rules (accrual, balance, notice period, medical exception, carry-over, contract boundary), which gives reasonable coverage. However, several operationally critical details are unspecified: partial-month accrual, half-day leave, the interaction between medical leave and balance, cross-year leave requests, the definition of 'month worked,' and whether the 5-day retroactive window measures from the first or last day of multi-day medical leave. These gaps would cause implementation ambiguity.",
    "high_confidence_areas": [
      "Non-negative balance invariant (BR-2) — clearly stated and unambiguous",
      "Rejected leave does not consume balance (BR-6) — explicitly stated",
      "Leave cannot span past contract end date (BR-7) — clearly stated",
      "10-day carry-over cap with forfeiture (BR-8) — clearly stated",
      "3-working-day advance notice for non-medical leave (BR-3) — clearly stated"
    ],
    "low_confidence_areas": [
      "Partial month accrual — spec does not define pro-rata rules",
      "Multi-day retroactive medical leave — 5-day window anchor point is ambiguous",
      "Cross-year leave requests — deduction and carry-over interaction unspecified",
      "Whether medical leave still requires sufficient balance or is granted regardless",
      "Definition of 'month worked' — calendar month vs 30-day period",
      "Leave request lifecycle — whether balance is held/reserved at submission or deducted only at approval"
    ],
    "assumptions": [
      "The 5-day retroactive window for medical leave is measured in calendar days, not working days",
      "Balance is deducted upon approval, not upon submission (since rejection restores balance per BR-6)",
      "Contract end date is inclusive — the employee is still employed on that date",
      "The carry-over calculation runs at the calendar year boundary (Jan 1) before any new accrual",
      "Working days exclude weekends (Saturday/Sunday) and company-recognized public holidays"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define how partial months are handled for accrual. An employee joining on the 15th — do they accrue 0.75 days for that month (pro-rata), the full 1.5 days, or nothing until the next full month?",
      "affected_stakeholders": ["Employees", "HR Department", "Payroll Team"],
      "options": ["Pro-rata accrual based on days worked in the month", "Full 1.5 days for any month with at least 1 day worked", "No accrual until the first full calendar month"],
      "recommendation": "Pro-rata accrual (days worked / working days in month × 1.5) is the fairest approach and aligns with most labor regulations."
    },
    {
      "type": "ambiguity",
      "description": "For multi-day retroactive medical leave, it is unclear whether the 5-day submission window is measured from the first day of absence or the last day of absence.",
      "affected_stakeholders": ["Employees", "HR Department"],
      "options": ["5 days from the first day of the medical leave period", "5 days from the last day of the medical leave period"],
      "recommendation": "Measure from the last day of absence — this is more employee-friendly and reflects that the employee may not be able to submit until they have recovered."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not clarify whether leave balance is reserved/held at submission time or only deducted upon manager approval. This affects concurrent request handling.",
      "affected_stakeholders": ["Employees", "Managers", "HR Department"],
      "options": ["Hold/reserve balance at submission, release on rejection", "Deduct only upon approval, validate balance again at approval time"],
      "recommendation": "Hold balance at submission to prevent double-booking. Release on rejection or cancellation. This prevents the race condition where two requests individually pass balance checks but together exceed the balance."
    },
    {
      "type": "ambiguity",
      "description": "Does the medical leave retroactive exception also exempt the employee from the non-negative balance requirement? Can an employee submit medical leave with zero balance?",
      "affected_stakeholders": ["Employees", "HR Department", "Finance / CFO"],
      "options": ["Medical leave still requires sufficient balance (only the timing rule is relaxed)", "Medical leave can go into negative balance as unpaid/special leave"],
      "recommendation": "Medical leave should still require sufficient balance. The spec explicitly states the balance cannot go negative with no exceptions listed. If unpaid medical leave is desired, it should be a separate leave type."
    }
  ],

  "rejection_reasons": []
}
